  function answerValueIsOnlyNumberAndCommonUnit(answerValue) {
    const value = String(answerValue || "").replace(/[.!?]+$/g, "").trim().toLowerCase().replace(/ё/g, "е").replace(/\s+/g, " " );
    if (!value) return false;
    return /^-?\d+(?:[.,]\d+)?\s*(?:кг|килограмм(?:а|ов)?|г|грамм(?:а|ов)?|км|километр(?:а|ов)?|м|метр(?:а|ов)?|дм|дециметр(?:а|ов)?|см|сантиметр(?:а|ов)?|мм|миллиметр(?:а|ов)?|руб\.?|р\.?|рубл(?:ь|я|ей)?)$/i.test(value);
  }
  function canonicalizeV312ShortUnitAnswer(taskText, answerValue) {
    const value = String(answerValue || "").replace(/[.!?]+$/g, "").trim();
    if (!value) return "";
    const question = (getQuestionSentence(taskText) || String(taskText || "")).toLowerCase().replace(/ё/g, "е");
    const answerNorm = value.toLowerCase().replace(/ё/g, "е");
    const numbers = value.match(/-?\d+(?:[.,]\d+)?/g) || [];
    const numeric = numbers.length ? numbers[numbers.length - 1] : "";
    if (!numeric) return "";
    if (/на\s+сколько/i.test(question)) return "";
    // V402.02: this legacy frontend helper used to rewrite full backend answers
    // such as «40 км проехала машина за два дня» and
    // «можно получить 4 кг сушеных груш» back to short Excel-style answers.
    // It may only normalize answers that are already just «number + unit».
    if (!answerValueIsOnlyNumberAndCommonUnit(value)) return "";
    const hasKg = /(^|[^а-яёa-z])кг(?=$|[^а-яёa-z])/i.test(answerNorm) || /килограмм/i.test(answerNorm);
    const hasKm = /(^|[^а-яёa-z])км(?=$|[^а-яёa-z])/i.test(answerNorm) || /километр/i.test(answerNorm);
    const hasRub = /руб/i.test(answerNorm) || /(^|[^а-яёa-z])р\.(?=$|[^а-яёa-z])/i.test(answerNorm);
    if (/сколько\s+килограммов/i.test(question) && hasKg) {
      return `Ответ: ${numeric} кг.`;
    }
    if ((/сколько\s+километров/i.test(question) || /какое\s+расстояние/i.test(question)) && hasKm) {
      return `Ответ: ${numeric} км.`;
    }
    if (/сколько\s+рубл/i.test(question) && hasRub) {
      return `Ответ: ${numeric} ${countedUnitForm("рублей", numeric)}.`;
    }
    return "";
  }
  function looksLikeV312TextProblemAuditTask(taskText) {
    const text = String(taskText || "").toLowerCase().replace(/ё/g, "е").replace(/\s+/g, " ").trim();
    if (!text || !/\d/.test(text)) return false;
    return Boolean(
      /в магазин привезли .* сколько килограммов .* осталось/.test(text) ||
      /в трех .* сколько .* в .*\?*$/.test(text) ||
      /у покупателя было .* купил .* сколько рублей осталось/.test(text) ||
      /за \d+ одинаковых .* заплатили .* сколько рублей стоит (?:один|одна|одно)/.test(text) ||
      /ехал .* со скоростью .* сколько километров он проехал/.test(text) ||
      /из двух городов .* навстречу .* какое расстояние между городами/.test(text) ||
      /\d+\s*\/\s*\d+ всех .* сколько/.test(text) ||
      /это \d+\s*\/\s*\d+ всех .* сколько всего/.test(text) ||
      /было по \d+ кг .* продали .* сколько килограммов .* осталось/.test(text) ||
      /поезд отправился в \d{1,2}:\d{2} .* во сколько он прибыл/.test(text)
    );
  }

  function splitV309Entries(raw) {
    const entries = {};
    String(raw || "").split(/\s*;\s*/).forEach((part) => {
      const clean = String(part || "").trim().replace(/[.!?]+$/g, "");
      if (!clean) return;
      let match = clean.match(/^\s*(.+?)\s*(?:—|–|-|:)\s*(.+?)\s*$/);
      if (!match) {
        const lessonMatch = clean.match(/^\s*(\d+)\s+урок\s+(.+?)\s*$/i);
        if (lessonMatch) {
          entries[`${Number(lessonMatch[1])} урок`] = String(lessonMatch[2] || "").trim().replace(/\s+/g, " ");
          return;
        }
        const priceMatch = clean.match(/^\s*(билет|программа|значок)\s+(-?\d+)\s*руб\.?\s*$/i);
        if (priceMatch) {
          const key = String(priceMatch[1] || "").trim().toLowerCase().replace(/ё/g, "е").replace(/\s+/g, " ");
          entries[key] = `${Number(priceMatch[2])} руб.`;
          return;
        }
        return;
      }
      const key = String(match[1] || "").trim().toLowerCase().replace(/ё/g, "е").replace(/\s+/g, " ");
      const value = String(match[2] || "").trim().replace(/\s+/g, " ");
      if (key) entries[key] = value;
    });
    return entries;
  }
  function makeV309CanonicalResult(taskText, steps, finalAnswer) {
    const cleanSteps = (Array.isArray(steps) ? steps : []).map((step) => String(step || "").trim().replace(/[.!?]+$/g, "")).filter(Boolean);
    const lines = ["Задача.", String(taskText || "").trim(), "Решение."];
    if (cleanSteps.length <= 1) {
      cleanSteps.forEach((step) => lines.push(`${step}.`));
    } else {
      cleanSteps.forEach((step, index) => lines.push(`${index + 1}) ${step}.`));
    }
    lines.push(`Ответ: ${String(finalAnswer || "").trim().replace(/[.!?]+$/g, "")}.`);
    return lines.join("\n").trim();
  }

