      if (denominators.length >= 2) {
        return `\u041A\u0430\u043A\u043E\u0439 \u043E\u0431\u0449\u0438\u0439 \u0437\u043D\u0430\u043C\u0435\u043D\u0430\u0442\u0435\u043B\u044C \u043F\u043E\u0434\u043E\u0439\u0434\u0451\u0442 \u0434\u043B\u044F ${denominators.join(", ")}? \u041D\u0430\u0439\u0434\u0438 \u0447\u0438\u0441\u043B\u043E, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0434\u0435\u043B\u0438\u0442\u0441\u044F \u043D\u0430 \u043A\u0430\u0436\u0434\u044B\u0439 \u0438\u0437 \u044D\u0442\u0438\u0445 \u0437\u043D\u0430\u043C\u0435\u043D\u0430\u0442\u0435\u043B\u0435\u0439.`;
      }
      return "\u0427\u0442\u043E \u043D\u0443\u0436\u043D\u043E \u0441\u0434\u0435\u043B\u0430\u0442\u044C \u0441\u043E \u0437\u043D\u0430\u043C\u0435\u043D\u0430\u0442\u0435\u043B\u044F\u043C\u0438, \u0447\u0442\u043E\u0431\u044B \u0434\u0440\u043E\u0431\u0438 \u0431\u044B\u043B\u043E \u0443\u0434\u043E\u0431\u043D\u043E \u0441\u043B\u043E\u0436\u0438\u0442\u044C \u0438\u043B\u0438 \u0441\u0440\u0430\u0432\u043D\u0438\u0442\u044C?";
